-- Auto-generated by colorsync — do not edit
vim.o.termguicolors = true
vim.cmd('hi clear')
if vim.fn.exists('syntax_on') then vim.cmd('syntax reset') end

-- Clear ALL highlight groups (including ones set by previous colorscheme)
for _, group in ipairs(vim.fn.getcompletion('', 'highlight')) do
  vim.api.nvim_set_hl(0, group, {})
end

vim.o.background = 'dark'
vim.g.colors_name = 'tokyo_night'

local c = {
  bg       = '#1a1b26',
  fg       = '#c0caf5',
  cursor   = '#c0caf5',
  black    = '#15161e',
  red      = '#f7768e',
  green    = '#9ece6a',
  yellow   = '#e0af68',
  blue     = '#7aa2f7',
  magenta  = '#bb9af7',
  cyan     = '#7dcfff',
  white    = '#a9b1d6',
  br_black   = '#414868',
  br_red     = '#f7768e',
  br_green   = '#9ece6a',
  br_yellow  = '#e0af68',
  br_blue    = '#7aa2f7',
  br_magenta = '#bb9af7',
  br_cyan    = '#7dcfff',
  br_white   = '#c0caf5',
}

local hi = function(group, opts) vim.api.nvim_set_hl(0, group, opts) end

-- Editor groups
hi('Normal',        { fg = c.fg, bg = c.bg })
hi('NormalFloat',   { fg = c.fg, bg = c.black })
